#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define NX 1024
#define NY 1024

void iso2dfd(float* input, float* output, int nx, int ny) {
    #pragma omp target teams distribute parallel for collapse(2) map(to: input[0:nx*ny]) map(from: output[0:nx*ny])
    for (int j = 2; j < ny - 2; j++) {
        for (int i = 2; i < nx - 2; i++) {
            output[j * nx + i] = (
                - 2.0f * input[j * nx + i]
                + input[j * nx + (i - 1)] + input[j * nx + (i + 1)]
                + input[(j - 1) * nx + i] + input[(j + 1) * nx + i]
            );
        }
    }
}

int main() {
    int nx = NX;
    int ny = NY;

    float* input = (float*)malloc(nx * ny * sizeof(float));
    float* output = (float*)malloc(nx * ny * sizeof(float));

    for (int i = 0; i < nx * ny; i++) {
        input[i] = static_cast<float>(i % 100);
        output[i] = 0.0f;
    }

    iso2dfd(input, output, nx, ny);

    for (int j = ny/2; j < ny/2 + 5; j++) {
        for (int i = nx/2; i < nx/2 + 5; i++) {
            printf("%0.2f ", output[j * nx + i]);
        }
        printf("\n");
    }

    free(input);
    free(output);

    return 0;
}
